22: // [#protodoc-title: Authorization service]
23: 
24: // The authorization service request messages used by external authorization :ref:`network filter
25: // <config_network_filters_ext_authz>` and :ref:`HTTP filter <config_http_filters_ext_authz>`.
26: 
27: // A generic interface for performing authorization check on incoming
28: // requests to a networked service.
29: service Authorization {
30:   // Performs authorization check based on the attributes associated with the
31:   // incoming request, and returns status `OK` or not `OK`.
32:   rpc Check(CheckRequest) returns (CheckResponse) {
33:   }
34: }
35: 
36: message CheckRequest {
37:   option (udpa.annotations.versioning).previous_message_type = "envoy.service.auth.v2.CheckRequest";
38: 
39:   // The request attributes.
40:   AttributeContext attributes = 1;
41: }
42: 
43: // HTTP attributes for a denied response.
44: message DeniedHttpResponse {
45:   option (udpa.annotations.versioning).previous_message_type =
46:       "envoy.service.auth.v2.DeniedHttpResponse";
47: 
48:   // This field allows the authorization service to send an HTTP response status code to the
49:   // downstream client. If not set, Envoy sends ``403 Forbidden`` HTTP status code by default.
50:   type.v3.HttpStatus status = 1;
51: 
52:   // This field allows the authorization service to send HTTP response headers
53:   // to the downstream client. Note that the :ref:`append field in HeaderValueOption <envoy_v3_api_field_config.core.v3.HeaderValueOption.append>` defaults to
54:   // false when used in this message.
55:   repeated config.core.v3.HeaderValueOption headers = 2;
56: 
57:   // This field allows the authorization service to send a response body data
58:   // to the downstream client.
59:   string body = 3;
60: }
61: 
62: // HTTP attributes for an OK response.
63: // [#next-free-field: 9]
64: message OkHttpResponse {
65:   option (udpa.annotations.versioning).previous_message_type =
66:       "envoy.service.auth.v2.OkHttpResponse";
67: 
68:   // HTTP entity headers in addition to the original request headers. This allows the authorization
69:   // service to append, to add or to override headers from the original request before
70:   // dispatching it to the upstream. Note that the :ref:`append field in HeaderValueOption <envoy_v3_api_field_config.core.v3.HeaderValueOption.append>` defaults to
71:   // false when used in this message. By setting the ``append`` field to ``true``,
72:   // the filter will append the correspondent header value to the matched request header.
73:   // By leaving ``append`` as false, the filter will either add a new header, or override an existing
74:   // one if there is a match.
75:   repeated config.core.v3.HeaderValueOption headers = 2;
76: 
77:   // HTTP entity headers to remove from the original request before dispatching
78:   // it to the upstream. This allows the authorization service to act on auth
79:   // related headers (like ``Authorization``), process them, and consume them.
80:   // Under this model, the upstream will either receive the request (if it's
81:   // authorized) or not receive it (if it's not), but will not see headers
82:   // containing authorization credentials.
83:   //
84:   // Pseudo headers (such as ``:authority``, ``:method``, ``:path`` etc), as well as
85:   // the header ``Host``, may not be removed as that would make the request
86:   // malformed. If mentioned in ``headers_to_remove`` these special headers will
87:   // be ignored.
88:   //
89:   // When using the HTTP service this must instead be set by the HTTP
90:   // authorization service as a comma separated list like so:
91:   // ``x-envoy-auth-headers-to-remove: one-auth-header, another-auth-header``.
92:   repeated string headers_to_remove = 5;
93: 
94:   // This field has been deprecated in favor of :ref:`CheckResponse.dynamic_metadata
95:   // <envoy_v3_api_field_service.auth.v3.CheckResponse.dynamic_metadata>`. Until it is removed,
96:   // setting this field overrides :ref:`CheckResponse.dynamic_metadata
97:   // <envoy_v3_api_field_service.auth.v3.CheckResponse.dynamic_metadata>`.
98:   google.protobuf.Struct dynamic_metadata = 3
99:       [deprecated = true, (envoy.annotations.deprecated_at_minor_version) = "3.0"];
100: 
101:   // This field allows the authorization service to send HTTP response headers
102:   // to the downstream client on success. Note that the :ref:`append field in HeaderValueOption <envoy_v3_api_field_config.core.v3.HeaderValueOption.append>`
103:   // defaults to false when used in this message.
104:   repeated config.core.v3.HeaderValueOption response_headers_to_add = 6;
105: 
106:   // This field allows the authorization service to set (and overwrite) query
107:   // string parameters on the original request before it is sent upstream.
108:   repeated config.core.v3.QueryParameter query_parameters_to_set = 7;
109: 
110:   // This field allows the authorization service to specify which query parameters
111:   // should be removed from the original request before it is sent upstream. Each
112:   // element in this list is a case-sensitive query parameter name to be removed.
113:   repeated string query_parameters_to_remove = 8;
114: }
115: 
116: // Intended for gRPC and Network Authorization servers ``only``.
117: // [#next-free-field: 6]
118: message CheckResponse {
119:   option (udpa.annotations.versioning).previous_message_type =
120:       "envoy.service.auth.v2.CheckResponse";
121: 
122:   // Status ``OK`` allows the request. Any other status indicates the request should be denied, and
123:   // for HTTP filter, if not overridden by :ref:`denied HTTP response status <envoy_v3_api_field_service.auth.v3.DeniedHttpResponse.status>`
124:   // Envoy sends ``403 Forbidden`` HTTP status code by default.
125:   google.rpc.Status status = 1;
126: 
127:   // An message that contains HTTP response attributes. This message is
128:   // used when the authorization service needs to send custom responses to the
129:   // downstream client or, to modify/add request headers being dispatched to the upstream.
130:   oneof http_response {
131:     // Supplies http attributes for a denied response.
132:     DeniedHttpResponse denied_response = 2;
133: 
134:     // Supplies http attributes for an ok response.
135:     OkHttpResponse ok_response = 3;
136: 
137:     // Supplies http attributes for an error response. This is used when the authorization
138:     // service encounters an internal error and wants to return custom headers and body to the
139:     // downstream client. When ``error_response`` is set, the ext_authz filter increments the
140:     // ``ext_authz_error`` stat and respects the :ref:`failure_mode_allow
141:     // <envoy_v3_api_field_extensions.filters.http.ext_authz.v3.ExtAuthz.failure_mode_allow>`
142:     // configuration. The HTTP status code, headers, and body are taken from the
143:     // :ref:`DeniedHttpResponse <envoy_v3_api_msg_service.auth.v3.DeniedHttpResponse>` message.
144:     // If the status field is not set, Envoy sends the status code configured via
145:     // :ref:`status_on_error <envoy_v3_api_field_extensions.filters.http.ext_authz.v3.ExtAuthz.status_on_error>`,
146:     // which defaults to ``403 Forbidden``.
147:     DeniedHttpResponse error_response = 5;
148:   }
149: 
150:   // Optional response metadata that will be emitted as dynamic metadata to be consumed by the next
151:   // filter. This metadata lives in a namespace specified by the canonical name of extension filter
152:   // that requires it:
153:   //
154:   // - :ref:`envoy.filters.http.ext_authz <config_http_filters_ext_authz_dynamic_metadata>` for HTTP filter.
155:   // - :ref:`envoy.filters.network.ext_authz <config_network_filters_ext_authz_dynamic_metadata>` for network filter.
156:   google.protobuf.Struct dynamic_metadata = 4;
157: }
