22: // [#protodoc-title: Rate limit service (RLS)]
23: 
24: service RateLimitService {
25:   // Determine whether rate limiting should take place.
26:   rpc ShouldRateLimit(RateLimitRequest) returns (RateLimitResponse) {
27:   }
28: }
29: 
30: // Main message for a rate limit request. The rate limit service is designed to be fully generic
31: // in the sense that it can operate on arbitrary hierarchical key/value pairs. The loaded
32: // configuration will parse the request and find the most specific limit to apply. In addition,
33: // a RateLimitRequest can contain multiple "descriptors" to limit on. When multiple descriptors
34: // are provided, the server will limit on *ALL* of them and return an OVER_LIMIT response if any
35: // of them are over limit. This enables more complex application level rate limiting scenarios
36: // if desired.
37: message RateLimitRequest {
38:   option (udpa.annotations.versioning).previous_message_type =
39:       "envoy.service.ratelimit.v2.RateLimitRequest";
40: 
41:   // All rate limit requests must specify a domain. This enables the configuration to be per
42:   // application without fear of overlap. E.g., "envoy".
43:   string domain = 1;
44: 
45:   // All rate limit requests must specify at least one RateLimitDescriptor. Each descriptor is
46:   // processed by the service (see below). If any of the descriptors are over limit, the entire
47:   // request is considered to be over limit.
48:   repeated envoy.extensions.common.ratelimit.v3.RateLimitDescriptor descriptors = 2;
49: 
50:   // Rate limit requests can optionally specify the number of hits a request adds to the matched
51:   // limit. If the value is not set in the message, a request increases the matched limit by 1.
52:   // This value can be overridden by setting filter state value ``envoy.ratelimit.hits_addend``
53:   // to the desired number. Invalid number (< 0) or number will be ignored.
54:   uint32 hits_addend = 3;
55: }
56: 
57: // A response from a ShouldRateLimit call.
58: // [#next-free-field: 8]
59: message RateLimitResponse {
60:   option (udpa.annotations.versioning).previous_message_type =
61:       "envoy.service.ratelimit.v2.RateLimitResponse";
62: 
63:   enum Code {
64:     // The response code is not known.
65:     UNKNOWN = 0;
66: 
67:     // The response code to notify that the number of requests are under limit.
68:     OK = 1;
69: 
70:     // The response code to notify that the number of requests are over limit.
71:     OVER_LIMIT = 2;
72:   }
73: 
74:   // Defines an actual rate limit in terms of requests per unit of time and the unit itself.
75:   message RateLimit {
76:     option (udpa.annotations.versioning).previous_message_type =
77:         "envoy.service.ratelimit.v2.RateLimitResponse.RateLimit";
78: 
79:     // Identifies the unit of of time for rate limit.
80:     // [#comment: replace by envoy/type/v3/ratelimit_unit.proto in v4]
81:     enum Unit {
82:       // The time unit is not known.
83:       UNKNOWN = 0;
84: 
85:       // The time unit representing a second.
86:       SECOND = 1;
87: 
88:       // The time unit representing a minute.
89:       MINUTE = 2;
90: 
91:       // The time unit representing an hour.
92:       HOUR = 3;
93: 
94:       // The time unit representing a day.
95:       DAY = 4;
96: 
97:       // The time unit representing a week.
98:       WEEK = 7;
99: 
100:       // The time unit representing a month.
101:       MONTH = 5;
102: 
103:       // The time unit representing a year.
104:       YEAR = 6;
105:     }
106: 
107:     // A name or description of this limit.
108:     string name = 3;
109: 
110:     // The number of requests per unit of time.
111:     uint32 requests_per_unit = 1;
112: 
113:     // The unit of time.
114:     Unit unit = 2;
115:   }
116: 
117:   // Cacheable quota for responses.
118:   // Quota can be granted at different levels: either for each individual descriptor or for the whole descriptor set.
119:   // This is a certain number of requests over a period of time.
120:   // The client may cache this result and apply the effective RateLimitResponse to future matching
121:   // requests without querying rate limit service.
122:   //
123:   // When quota expires due to timeout, a new RLS request will also be made.
124:   // The implementation may choose to preemptively query the rate limit server for more quota on or
125:   // before expiration or before the available quota runs out.
126:   // [#not-implemented-hide:]
127:   message Quota {
128:     // Number of matching requests granted in quota. Must be 1 or more.
129:     uint32 requests = 1 [(validate.rules).uint32 = {gt: 0}];
130: 
131:     oneof expiration_specifier {
132:       // Point in time at which the quota expires.
133:       google.protobuf.Timestamp valid_until = 2;
134:     }
135: 
136:     // The unique id that is associated with each Quota either at individual descriptor level or whole descriptor set level.
137:     //
138:     // For a matching policy with boolean logic, for example, match: "request.headers['environment'] == 'staging' || request.headers['environment'] == 'dev'"),
139:     // the request_headers action produces a distinct list of descriptors for each possible value of the ‘environment’ header even though the granted quota is same.
