{"content":"1: syntax = "proto3";
2: 
3: package envoy.service.status.v3;
4: 
5: import "envoy/admin/v3/config_dump_shared.proto";
6: import "envoy/config/core/v3/base.proto";
7: import "envoy/type/matcher/v3/node.proto";
8: 
9: import "google/api/annotations.proto";
10: import "google/protobuf/any.proto";
11: import "google/protobuf/timestamp.proto";
12: 
13: import "envoy/annotations/deprecation.proto";
14: import "udpa/annotations/status.proto";
15: import "udpa/annotations/versioning.proto";
16: 
17: option java_package = "io.envoyproxy.envoy.service.status.v3";
18: option java_outer_classname = "CsdsProto";
19: option java_multiple_files = true;
20: option go_package = "github.com/envoyproxy/go-control-plane/envoy/service/status/v3;statusv3";
21: option (udpa.annotations.file_status).package_version_status = ACTIVE;
22: 
23: // [#protodoc-title: Client status discovery service (CSDS)]
24: 
25: // CSDS is Client Status Discovery Service. It can be used to get the status of
26: // an xDS-compliant client from the management server's point of view. It can
27: // also be used to get the current xDS states directly from the client.
28: service ClientStatusDiscoveryService {
29:   rpc StreamClientStatus(stream ClientStatusRequest) returns (stream ClientStatusResponse) {
30:   }
31: 
32:   rpc FetchClientStatus(ClientStatusRequest) returns (ClientStatusResponse) {
33:     option (google.api.http).post = "/v3/discovery:client_status";
34:     option (google.api.http).body = "*";
35:   }
36: }
37: 
38: // Status of a config from a management server view.
39: enum ConfigStatus {
40:   // Status info is not available/unknown.
41:   UNKNOWN = 0;
42: 
43:   // Management server has sent the config to client and received ACK.
44:   SYNCED = 1;
45: 
46:   // Config is not sent.
47:   NOT_SENT = 2;
48: 
49:   // Management server has sent the config to client but hasn’t received
50:   // ACK/NACK.
51:   STALE = 3;
52: 
53:   // Management server has sent the config to client but received NACK. The
54:   // attached config dump will be the latest config (the rejected one), since
55:   // it is the persisted version in the management server.
56:   ERROR = 4;
57: }
58: 
59: // Config status from a client-side view.
60: enum ClientConfigStatus {
61:   // Config status is not available/unknown.
62:   CLIENT_UNKNOWN = 0;
63: 
64:   // Client requested the config but hasn't received any config from management
65:   // server yet.
66:   CLIENT_REQUESTED = 1;
67: 
68:   // Client received the config and replied with ACK.
69:   CLIENT_ACKED = 2;
70: 
71:   // Client received the config and replied with NACK. Notably, the attached
72:   // config dump is not the NACKed version, but the most recent accepted one. If
73:   // no config is accepted yet, the attached config dump will be empty.
74:   CLIENT_NACKED = 3;
75: 
76:   // Client received an error from the control plane. The attached config
77:   // dump is the most recent accepted one. If no config is accepted yet,
78:   // the attached config dump will be empty.
79:   CLIENT_RECEIVED_ERROR = 4;
80: }
81: 
82: // Request for client status of clients identified by a list of NodeMatchers.
83: message ClientStatusRequest {
84:   option (udpa.annotations.versioning).previous_message_type =
85:       "envoy.service.status.v2.ClientStatusRequest";
86: 
87:   // Management server can use these match criteria to identify clients.
88:   // The match follows OR semantics.
89:   repeated type.matcher.v3.NodeMatcher node_matchers = 1;
90: 
91:   // The node making the csds request.
92:   config.core.v3.Node node = 2;
93: 
94:   // If true, the server will not include the resource contents in the response
95:   // (i.e., the generic_xds_configs.xds_config field will not be populated).
96:   // [#not-implemented-hide:]
97:   bool exclude_resource_contents = 3;
98: }
99: 
100: // Detailed config (per xDS) with status.
101: // [#next-free-field: 8]
102: message PerXdsConfig {
103:   option (udpa.annotations.versioning).previous_message_type =
104:       "envoy.service.status.v2.PerXdsConfig";
105: 
106:   // Config status generated by management servers. Will not be present if the
107:   // CSDS server is an xDS client.
108:   ConfigStatus status = 1;
109: 
110:   // Client config status is populated by xDS clients. Will not be present if
111:   // the CSDS server is an xDS server. No matter what the client config status
112:   // is, xDS clients should always dump the most recent accepted xDS config.
113:   //
114:   // .. attention::
115:   //   This field is deprecated. Use :ref:`ClientResourceStatus
116:   //   <envoy_v3_api_enum_admin.v3.ClientResourceStatus>` for per-resource
117:   //   config status instead.
118:   ClientConfigStatus client_status = 7
119:       [deprecated = true, (envoy.annotations.deprecated_at_minor_version) = "3.0"];
120: 
121:   oneof per_xds_config {
122:     admin.v3.ListenersConfigDump listener_config = 2;
123: 
124:     admin.v3.ClustersConfigDump cluster_config = 3;
125: 
126:     admin.v3.RoutesConfigDump route_config = 4;
127: 
128:     admin.v3.ScopedRoutesConfigDump scoped_route_config = 5;
129: 
130:     admin.v3.EndpointsConfigDump endpoint_config = 6;
131:   }
132: }
133: 
134: // All xds configs for a particular client.
135: message ClientConfig {
136:   option (udpa.annotations.versioning).previous_message_type =
137:       "envoy.service.status.v2.ClientConfig";
138: 
139:   // GenericXdsConfig is used to specify the config status and the dump
140:   // of any xDS resource identified by their type URL. It is the generalized
141:   // version of the now deprecated ListenersConfigDump, ClustersConfigDump etc
142:   // [#next-free-field: 10]
143:   message GenericXdsConfig {
144:     // Type_url represents the fully qualified name of xDS resource type
145:     // like envoy.v3.Cluster, envoy.v3.ClusterLoadAssignment etc.
146:     string type_url = 1;
147: 
148:     // Name of the xDS resource
149:     string name = 2;
150: 
151:     // This is the :ref:`version_info <envoy_v3_api_field_service.discovery.v3.DiscoveryResponse.version_info>`
152:     // in the last processed xDS discovery response. If there are only
153:     // static bootstrap listeners, this field will be ""
154:     string version_info = 3;
155: 
156:     // The xDS resource config. Actual content depends on the type
157:     google.protobuf.Any xds_config = 4;
158: 
159:     // Timestamp when the xDS resource was last updated
160:     google.protobuf.Timestamp last_updated = 5;
161: 
162:     // Per xDS resource config status. It is generated by management servers.
163:     // It will not be present if the CSDS server is an xDS client.
164:     ConfigStatus config_status = 6;
165: 
166:     // Per xDS resource status from the view of a xDS client
167:     admin.v3.ClientResourceStatus client_status = 7;
168: 
169:     // Set if the last update failed, cleared after the next successful
170:     // update. The *error_state* field contains the rejected version of
171:     // this particular resource along with the reason and timestamp. For
172:     // successfully updated or acknowledged resource, this field should
173:     // be empty.
174:     // [#not-implemented-hide:]
175:     admin.v3.UpdateFailureState error_state = 8;
176: 
177:     // Is static resource is true if it is specified in the config supplied
178:     // through the file at the startup.
179:     bool is_static_resource = 9;
180:   }
181: 
182:   // Node for a particular client.
183:   config.core.v3.Node node = 1;
184: 
185:   // This field is deprecated in favor of generic_xds_configs which is
186:   // much simpler and uniform in structure.
187:   repeated PerXdsConfig xds_config = 2
188:       [deprecated = true, (envoy.annotations.deprecated_at_minor_version) = "3.0"];
189: 
190:   // Represents generic xDS config and the exact config structure depends on
191:   // the type URL (like Cluster if it is CDS)
192:   repeated GenericXdsConfig generic_xds_configs = 3;
193: 
194:   // For xDS clients, the scope in which the data is used.
195:   // For example, gRPC indicates the data plane target or that the data is
196:   // associated with gRPC server(s).
197:   string client_scope = 4;
198: }
199: 
200: message ClientStatusResponse {
201:   option (udpa.annotations.versioning).previous_message_type =
202:       "envoy.service.status.v2.ClientStatusResponse";
203: 
