19: // [#protodoc-title: gRPC Event Reporting Service]
20: 
21: // [#not-implemented-hide:]
22: // Service for streaming different types of events from Envoy to a server. The examples of
23: // such events may be health check or outlier detection events.
24: service EventReportingService {
25:   // Envoy will connect and send StreamEventsRequest messages forever.
26:   // The management server may send StreamEventsResponse to configure event stream. See below.
27:   // This API is designed for high throughput with the expectation that it might be lossy.
28:   rpc StreamEvents(stream StreamEventsRequest) returns (stream StreamEventsResponse) {
29:   }
30: }
31: 
32: // [#not-implemented-hide:]
33: // An events envoy sends to the management server.
34: message StreamEventsRequest {
35:   option (udpa.annotations.versioning).previous_message_type =
36:       "envoy.service.event_reporting.v2alpha.StreamEventsRequest";
37: 
38:   message Identifier {
39:     option (udpa.annotations.versioning).previous_message_type =
40:         "envoy.service.event_reporting.v2alpha.StreamEventsRequest.Identifier";
41: 
42:     // The node sending the event messages over the stream.
43:     config.core.v3.Node node = 1 [(validate.rules).message = {required: true}];
44:   }
45: 
46:   // Identifier data that will only be sent in the first message on the stream. This is effectively
47:   // structured metadata and is a performance optimization.
48:   Identifier identifier = 1;
49: 
50:   // Batch of events. When the stream is already active, it will be the events occurred
51:   // since the last message had been sent. If the server receives unknown event type, it should
52:   // silently ignore it.
53:   //
54:   // The following events are supported:
55:   //
56:   // * :ref:`HealthCheckEvent <envoy_v3_api_msg_data.core.v3.HealthCheckEvent>`
57:   // * :ref:`OutlierDetectionEvent <envoy_v3_api_msg_data.cluster.v3.OutlierDetectionEvent>`
58:   repeated google.protobuf.Any events = 2 [(validate.rules).repeated = {min_items: 1}];
59: }
60: 
61: // [#not-implemented-hide:]
62: // The management server may send envoy a StreamEventsResponse to tell which events the server
63: // is interested in. In future, with aggregated event reporting service, this message will
64: // contain, for example, clusters the envoy should send events for, or event types the server
65: // wants to process.
66: message StreamEventsResponse {
67:   option (udpa.annotations.versioning).previous_message_type =
68:       "envoy.service.event_reporting.v2alpha.StreamEventsResponse";
69: }
